import React, { useEffect, useState } from "react";
import "./ExpenseUI.css";

function AddTicket({ employee }) {
  const [form, setForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
  });

  const [ticketList, setTicketList] = useState([]);

  const fetchTickets = async () => {
    try {
      const res = await fetch(
        `https://prasa-backend-1.onrender.com/ticket/${employee.empld}`
      );
      const data = await res.json();
      setTicketList(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchTickets();
  }, []);

  const saveTicket = async () => {
    try {
      await fetch("https://prasa-backend-1.onrender.com/ticket/add", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...form, empld: employee.empld }),
      });

      alert("Ticket Expense Added!");
      fetchTickets();
      setForm({
        ticket_date: "",
        purpose: "",
        assigned_to: "",
        amount: "",
      });
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div className="expense-container">
      <h2 className="page-title">Ticket Expense</h2>

      <div className="expense-card">
        <div className="grid-3">
          <input
            type="date"
            className="input-box"
            value={form.ticket_date}
            onChange={(e) =>
              setForm({ ...form, ticket_date: e.target.value })
            }
          />

          <input
            type="text"
            className="input-box"
            placeholder="Purpose"
            value={form.purpose}
            onChange={(e) => setForm({ ...form, purpose: e.target.value })}
          />

          <input
            type="text"
            className="input-box"
            placeholder="Assigned To"
            value={form.assigned_to}
            onChange={(e) =>
              setForm({ ...form, assigned_to: e.target.value })
            }
          />

          <input
            type="number"
            className="input-box"
            placeholder="Amount"
            value={form.amount}
            onChange={(e) => setForm({ ...form, amount: e.target.value })}
          />
        </div>

        <button className="save-btn" onClick={saveTicket}>
          Save Ticket Expense
        </button>
      </div>

      <h3 className="section-title">Ticket History</h3>

      {ticketList.length === 0 ? (
        <p className="empty">No ticket records</p>
      ) : (
        <div className="table-wrapper">
          <table className="custom-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>Purpose</th>
                <th>Assigned</th>
                <th>Amount</th>
              </tr>
            </thead>
            <tbody>
              {ticketList.map((t, i) => (
                <tr key={i}>
                  <td>{t.ticket_date}</td>
                  <td>{t.purpose}</td>
                  <td>{t.assigned_to}</td>
                  <td>₹{t.amount}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default AddTicket;
